{"operationName":"GetArticleInEventList","variables":{"limit":1,"eventTypes":["0.3.1.0.1","0.17.0.0.0","1.50.0.0.0","0.50.4.0.0","0.50.4.0.0","0.6.0.0.0","0.50.4.0.0","0.28.0.0.0","0.37.0.0.0","0.50.4.0.0"],"promoted":true,"sort":"stickyInSearchResults"},"query":"query GetArticleInEventList($limit: Float, $eventTypes: [String!], $promoted: Boolean, $target: [EventTarget!], $sort: String) {
  articles(
    limit: $limit
    eventTypes: $eventTypes
    promoted: $promoted
    target: $target
    sort: $sort
  ) {
    data {
      id
      title
      intro
      image {
        alt
        caption
        styles {
          style_12_12_xl
